sql:
SELECT element_name
FROM elements
WHERE atomic_mass = (SELECT MAX(atomic_mass) FROM elements);

SELECT model_name
FROM theoretical_models
WHERE element_id = 2;

SELECT element_name
FROM elements
WHERE element_id IN (
  SELECT DISTINCT element_id
  FROM access_logs
);

SELECT element_name
FROM elements
ORDER BY atomic_number ASC;

SELECT COUNT(*) AS num_elements
FROM element_configurations
WHERE configuration = '1s^1' AND config_date = '2023-05-01';

